const ctx = $input.first().json;
if (!ctx.execution_id) throw new Error('Missing execution_id');
if (!ctx.results?.resume_profile) throw new Error('Missing resume_profile from Phase 3');

const profile = ctx.results.career_goals || {};
const skills = ctx.results.resume_profile.skills_matrix || [];

const prompt = `You are an expert Recruitment AI.\n\nTarget Type: Full-Time Job\nCareer Profile: ${JSON.stringify(profile)}\nTop Skills: ${skills.filter(s => s.is_primary).map(s => s.normalized).join(', ')}`;

return [{
  json: {
    ctx,
    prompt,
    model: $env.MODEL_SEARCH_STRATEGY || 'google/gemini-flash-1.5'
  }
}];

