const req = $('Init & Build Prompt').item.json;
const llmRes = $input.first().json;

let parsed;
try {
  parsed = JSON.parse(llmRes.choices[0].message.content);
} catch (e) {
  // Fallback
  parsed = { strategies: [{ name: 'Fallback', query: req.ctx.results?.career_goals?.inferred_roles?.[0] || 'Software Engineer' }] };
}

// We will split the strategies into individual items to fan out the API requests
return parsed.strategies.map(s => ({
  json: { ctx: req.ctx, strategy: s }
}));

const strategy = $input.first().json.strategy;

// MOCK CONNECTOR: If APIs fail or no keys, we provide realistic mock data
return [{
  json: {
    source: 'mock_aggregator',
    results: [
      {
        title: 'Senior ' + strategy.query.replace(/["()]/g, '').split(' ')[0] + ' Engineer',
        company: 'TechCorp Inc',
        location: 'Remote',
        salary_min: 120000,
        salary_max: 180000,
        url: 'https://techcorp.com/careers/1',
        description: 'We are looking for a great engineer with skills in ' + strategy.query
      },
      {
        title: strategy.query.replace(/["()]/g, '') + ' Developer',
        company: 'Startup LLC',
        location: 'New York, NY',
        salary_min: 90000,
        salary_max: 130000,
        url: 'https://startup.io/jobs/2',
        description: 'Fast-paced environment looking for ' + strategy.query
      }
    ]
  }
}];

const crypto = require('crypto');
const allItems = $input.all();
const ctx = $('Parse & Fan Out').item.json.ctx;

const rawJobs = [];

// Process SerpApi
const serpItems = $('Search SerpApi').all();
serpItems.forEach(item => {
  if (item.json.error) return;
  const jobs = item.json.jobs_results || [];
  jobs.forEach(j => {
    rawJobs.push({
      title: j.title,
      company_name: j.company_name,
      location: j.location,
      remote_status: j.location.toLowerCase().includes('remote') ? 'remote' : 'onsite',
      employment_type: 'full_time',
      salary_min: null,
      salary_max: null,
      salary_currency: null,
      description: j.description,
      apply_url: j.share_link || j.related_links?.[0]?.link || 'Unknown',
      source: 'serpapi'
    });
  });
});

// Process Adzuna
const adzunaItems = $('Search Adzuna').all();
adzunaItems.forEach(item => {
  if (item.json.error) return;
  const jobs = item.json.results || [];
  jobs.forEach(j => {
    rawJobs.push({
      title: j.title,
      company_name: j.company.display_name,
      location: j.location.display_name,
      remote_status: j.location.display_name.toLowerCase().includes('remote') ? 'remote' : 'onsite',
      employment_type: j.contract_type === 'contract' ? 'contract' : 'full_time',
      salary_min: j.salary_min,
      salary_max: j.salary_max,
      salary_currency: 'USD',
      description: j.description,
      apply_url: j.redirect_url,
      source: 'adzuna'
    });
  });
});

// Process Mock
const mockItems = $('Mock Connector').all();
mockItems.forEach(item => {
  if (item.json.error) return;
  const jobs = item.json.results || [];
  jobs.forEach(j => {
    rawJobs.push({
      title: j.title,
      company_name: j.company,
      location: j.location,
      remote_status: j.location.toLowerCase().includes('remote') ? 'remote' : 'onsite',
      employment_type: 'full_time',
      salary_min: j.salary_min,
      salary_max: j.salary_max,
      salary_currency: 'USD',
      description: j.description,
      apply_url: j.url,
      source: 'mock'
    });
  });
});

// Deduplicate using SHA256(Title + Company)
const deduped = [];
const seenHashes = new Set();

rawJobs.forEach(job => {
  if (!job.title || !job.company_name) return;
  const hashStr = (job.title.trim().toLowerCase() + '|' + job.company_name.trim().toLowerCase());
  const hash = crypto.createHash('sha256').update(hashStr).digest('hex');

  if (!seenHashes.has(hash)) {
    seenHashes.add(hash);
    job.dedup_hash = hash;
    deduped.push(job);
  }
});

// We output the deduplicated jobs one by one for the enrichment/scoring loop
return deduped.map(job => ({
  json: { job, ctx }
}));

const allItems = $input.all();
const ctx = $('Parse & Fan Out').item.json.ctx;

// Collect all scored jobs
let jobs = allItems.map(i => i.json);

// Rank by score descending
jobs.sort((a, b) => (b.match_score || 0) - (a.match_score || 0));

// Take top 20 for pipeline to avoid context explosion
const topJobs = jobs.slice(0, 20);

// Update context
const newCtx = { ...ctx };
newCtx.results = newCtx.results || {};
newCtx.results.opportunities = newCtx.results.opportunities || [];
newCtx.results.opportunities.push(...topJobs);
newCtx.agents_completed = [...(newCtx.agents_completed || []), 'job_search'];

return [{ json: { ctx: newCtx, jobsToInsert: topJobs } }];

